// frontend/src/pages/Dashboard.js
import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import PlaceCard from '../components/PlaceCard';
import Analytics from '../components/Analytics';
import Toast from '../components/Toast';
import ProfileModal from '../components/ProfileModal';
import { getPlaces, getPrediction } from '../services/api';

const CATEGORIES = [
  { key: 'all',        label: 'All',         icon: '🗺️' },
  { key: 'mall',       label: 'Malls',       icon: '🛍️' },
  { key: 'cafe',       label: 'Cafes',       icon: '☕' },
  { key: 'gym',        label: 'Gyms',        icon: '💪' },
  { key: 'restaurant', label: 'Restaurants', icon: '🍽️' },
];

function getDistanceKm(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const dL = ((lat2 - lat1) * Math.PI) / 180;
  const dO = ((lon2 - lon1) * Math.PI) / 180;
  const a  = Math.sin(dL/2)**2 + Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dO/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

function formatDistance(km) {
  return km < 1 ? `${Math.round(km * 1000)} m away` : `${km.toFixed(1)} km away`;
}

async function reverseGeocode(lat, lng) {
  try {
    const res  = await fetch(
      `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json`,
      { headers: { 'Accept-Language': 'en' } }
    );
    const data = await res.json();
    const addr = data.address || {};
    return [addr.suburb || addr.neighbourhood, addr.city || addr.town || addr.village]
      .filter(Boolean).slice(0, 2).join(', ') || 'Your Location';
  } catch { return 'Your Location'; }
}

export default function Dashboard() {
  const { user, logout } = useAuth();

  const [places, setPlaces]         = useState([]);
  const [predictions, setPred]      = useState({});
  const [category, setCategory]     = useState('all');
  const [search, setSearch]         = useState('');
  const [toast, setToast]           = useState(null);
  const [userCoords, setUserCoords] = useState(null);
  const [locationName, setLocName]  = useState('');
  const [locLoading, setLocLoading] = useState(false);
  const [loading, setLoading]       = useState(false);
  const [tab, setTab]               = useState('Explore');
  const [lastUpdated, setLastUpd]   = useState(null);
  const [profileOpen, setProfile]   = useState(false);
  const [searchFocused, setFocused] = useState(false);
  const refreshRef                  = useRef(null);
  const searchRef                   = useRef(null);

  const showToast = (msg, type = 'success') => setToast({ message: msg, type });

  const attachDistances = useCallback((list, coords) => {
    if (!coords) return list;
    return list
      .map(p => {
        if (p.latitude && p.longitude) {
          const km = getDistanceKm(coords.lat, coords.lng, parseFloat(p.latitude), parseFloat(p.longitude));
          return { ...p, distance_km: km, distance_label: formatDistance(km) };
        }
        return { ...p, distance_label: null };
      })
      .sort((a, b) => {
        if (a.distance_km != null && b.distance_km != null) return a.distance_km - b.distance_km;
        if (a.distance_km != null) return -1;
        return 1;
      });
  }, []);

  const loadPlaces = useCallback(async (cat, q, coords, silent = false) => {
    if (!silent) setLoading(true);
    try {
      // Pass lat/lng so backend can bias OSM results to user location
      const lat = coords?.lat ?? userCoords?.lat;
      const lng = coords?.lng ?? userCoords?.lng;
      let data  = await getPlaces(cat, q, lat, lng);
      data      = attachDistances(data, coords ?? userCoords);
      setPlaces(data);

      const predEntries = await Promise.all(
        data.map(p => getPrediction(p.id, p.category || 'mall').then(pred => [p.id, pred]))
      );
      setPred(Object.fromEntries(predEntries));
      setLastUpd(new Date());
    } catch {
      if (!silent) showToast('Could not load places. Make sure backend is running.', 'error');
    } finally {
      if (!silent) setLoading(false);
    }
  }, [userCoords, attachDistances]);

  // Auto-refresh every 5 min
  useEffect(() => {
    refreshRef.current = setInterval(() => {
      loadPlaces(category, search, userCoords, true);
    }, 5 * 60 * 1000);
    return () => clearInterval(refreshRef.current);
  }, [category, search, userCoords]);

  // Search debounce
  useEffect(() => {
    const t = setTimeout(() => {
      if (search.trim().length > 0 || places.length === 0) {
        loadPlaces(category, search, userCoords, false);
      }
    }, 500);
    return () => clearTimeout(t);
  }, [search, category]);

  const detectLocation = () => {
    if (!navigator.geolocation) { showToast('Geolocation not supported.', 'error'); return; }
    setLocLoading(true);
    setLocName('Detecting location...');
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        const coords = { lat: pos.coords.latitude, lng: pos.coords.longitude };
        setUserCoords(coords);
        const name = await reverseGeocode(coords.lat, coords.lng);
        setLocName(name);
        setLocLoading(false);
        showToast(`Location detected: ${name}`);
        loadPlaces(category, search, coords, false);
      },
      () => { setLocName(''); setLocLoading(false); showToast('Location access denied.', 'error'); },
      { enableHighAccuracy: true, timeout: 10000 }
    );
  };

  const s = {
    page:  { minHeight: '100vh', background: '#f4f5f7', fontFamily: 'sans-serif' },
    nav: {
      background: '#fff', borderBottom: '1px solid #eee', padding: '0 24px',
      height: '64px', display: 'flex', alignItems: 'center',
      justifyContent: 'space-between', position: 'sticky', top: 0, zIndex: 100,
    },
    logo:  { fontSize: '20px', fontWeight: '800', color: '#1a1a2e', letterSpacing: '-0.5px' },
    logoG: { color: '#1D9E75' },
    navTabs: { display: 'flex', gap: '4px' },
    navTab: (active) => ({
      padding: '8px 18px', border: 'none',
      background: active ? '#e8f8f2' : 'transparent',
      color: active ? '#0f6e56' : '#888', borderRadius: '10px',
      fontSize: '14px', fontWeight: active ? '700' : '500', cursor: 'pointer',
    }),
    navRight: { display: 'flex', alignItems: 'center', gap: '10px' },
    // Profile avatar — clickable
    avatarBtn: {
      display: 'flex', alignItems: 'center', gap: '8px',
      padding: '6px 12px', borderRadius: '40px', border: '1.5px solid #eee',
      background: '#fff', cursor: 'pointer', transition: 'all .15s',
    },
    avatar: {
      width: '32px', height: '32px', borderRadius: '50%',
      background: 'linear-gradient(135deg, #1D9E75, #0f6e56)',
      color: '#fff', display: 'flex', alignItems: 'center',
      justifyContent: 'center', fontWeight: '700', fontSize: '13px', flexShrink: 0,
    },
    main: { maxWidth: '1200px', margin: '0 auto', padding: '24px 20px', width: '100%' },
    searchRow: { display: 'flex', gap: '10px', marginBottom: '12px', flexWrap: 'wrap' },
    searchWrap: {
      flex: 1, minWidth: '220px', position: 'relative',
    },
    searchBox: {
      width: '100%', padding: '13px 18px 13px 44px', boxSizing: 'border-box',
      border: `1.5px solid ${searchFocused ? '#1D9E75' : '#e8e8e8'}`,
      borderRadius: '14px', fontSize: '14px', outline: 'none',
      background: '#fff', boxShadow: '0 2px 8px rgba(0,0,0,0.04)',
      transition: 'border-color .2s',
    },
    searchIcon: {
      position: 'absolute', left: '15px', top: '50%',
      transform: 'translateY(-50%)', fontSize: '16px', pointerEvents: 'none',
    },
    locBtn: {
      padding: '13px 18px', background: userCoords ? '#1D9E75' : '#1a1a2e',
      color: '#fff', border: 'none', borderRadius: '14px',
      fontSize: '13px', fontWeight: '600', cursor: 'pointer', whiteSpace: 'nowrap',
      transition: 'background .2s',
    },
    locPill: {
      display: 'inline-flex', alignItems: 'center', gap: '6px',
      background: '#e8f8f2', color: '#0f6e56', padding: '7px 14px',
      borderRadius: '40px', fontSize: '13px', fontWeight: '600',
      marginBottom: '14px', border: '1.5px solid #b7ebd0',
    },
    catRow: { display: 'flex', gap: '8px', marginBottom: '16px', flexWrap: 'wrap' },
    catBtn: (active) => ({
      padding: '8px 16px', display: 'flex', alignItems: 'center', gap: '6px',
      border: '1.5px solid ' + (active ? '#1D9E75' : '#e8e8e8'),
      borderRadius: '40px', background: active ? '#e8f8f2' : '#fff',
      color: active ? '#0f6e56' : '#666', fontSize: '13px',
      fontWeight: active ? '700' : '500', cursor: 'pointer',
    }),
    metaRow: {
      display: 'flex', justifyContent: 'space-between', alignItems: 'center',
      marginBottom: '14px', flexWrap: 'wrap', gap: '8px',
    },
    grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '16px' },
    empty: { textAlign: 'center', padding: '80px 20px', color: '#bbb' },
  };

  return (
    <div style={s.page}>
      {/* Navbar */}
      <nav style={s.nav}>
        <div style={s.logo}>Visit<span style={s.logoG}>Wise</span> AI</div>

        <div style={s.navTabs}>
          {['Explore', 'Analytics'].map(t => (
            <button key={t} style={s.navTab(tab === t)} onClick={() => setTab(t)}>{t}</button>
          ))}
        </div>

        {/* Profile button — click to open modal */}
        <div style={s.navRight}>
          <button style={s.avatarBtn} onClick={() => setProfile(true)}>
            <div style={s.avatar}>{user?.name?.charAt(0).toUpperCase()}</div>
            <span style={{ fontSize: '14px', fontWeight: '600', color: '#1a1a2e' }}>
              {user?.name?.split(' ')[0]}
            </span>
            <span style={{ fontSize: '11px', color: '#bbb' }}>▼</span>
          </button>
        </div>
      </nav>

      <div style={s.main}>

        {/* ── EXPLORE TAB ── */}
        {tab === 'Explore' && (
          <>
            {/* Search */}
            <div style={s.searchRow}>
              <div style={s.searchWrap}>
                <span style={s.searchIcon}>🔍</span>
                <input
                  ref={searchRef}
                  style={s.searchBox}
                  placeholder="Search any mall, cafe, gym, restaurant..."
                  value={search}
                  onChange={e => setSearch(e.target.value)}
                  onFocus={() => setFocused(true)}
                  onBlur={() => setFocused(false)}
                />
              </div>
              <button style={s.locBtn} onClick={detectLocation} disabled={locLoading}>
                {locLoading ? '⏳ Detecting...' : userCoords ? '📍 Location On' : '📍 Near Me'}
              </button>
            </div>

            {/* Location pill */}
            {locationName && (
              <div style={s.locPill}>
                📍 <span>{locationName}</span>
                {userCoords && <span style={{ fontSize: '11px', opacity: 0.7, fontWeight: '400' }}>· Sorted by distance</span>}
              </div>
            )}

            {/* Hint when search is empty */}
            {!search && places.length === 0 && !loading && (
              <div style={{
                background: 'linear-gradient(135deg, #e8f8f2, #f0fdf8)',
                border: '1.5px solid #b7ebd0', borderRadius: '16px',
                padding: '24px', textAlign: 'center', marginBottom: '20px',
              }}>
                <div style={{ fontSize: '32px', marginBottom: '10px' }}>🔍</div>
                <div style={{ fontWeight: '700', fontSize: '16px', color: '#0f6e56', marginBottom: '6px' }}>
                  Search Any Place
                </div>
                <div style={{ fontSize: '13px', color: '#888' }}>
                  Type a mall, cafe, gym, or restaurant name to see real-time crowd predictions
                </div>
                <div style={{ display: 'flex', gap: '8px', justifyContent: 'center', marginTop: '14px', flexWrap: 'wrap' }}>
                  {['Select CityWalk', 'Blue Tokai', 'Anytime Fitness', 'McDonald\'s'].map(s => (
                    <button key={s} onClick={() => setSearch(s)} style={{
                      padding: '6px 14px', background: '#fff', border: '1.5px solid #ddd',
                      borderRadius: '20px', fontSize: '13px', color: '#555', cursor: 'pointer',
                    }}>
                      {s}
                    </button>
                  ))}
                </div>
              </div>
            )}

            {/* Category filter */}
            <div style={s.catRow}>
              {CATEGORIES.map(c => (
                <button key={c.key} style={s.catBtn(category === c.key)} onClick={() => setCategory(c.key)}>
                  {c.icon} {c.label}
                </button>
              ))}
            </div>

            {/* Result meta */}
            {!loading && places.length > 0 && (
              <div style={s.metaRow}>
                <span style={{ fontSize: '13px', color: '#aaa' }}>
                  {places.length} results
                  {search ? ` for "${search}"` : ''}
                  {userCoords ? ' · Sorted by distance' : ''}
                  {lastUpdated ? ` · ${lastUpdated.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' })}` : ''}
                </span>
                <button
                  onClick={() => loadPlaces(category, search, userCoords, false)}
                  style={{ padding: '6px 14px', border: '1.5px solid #e8e8e8', background: '#fff', color: '#888', borderRadius: '20px', fontSize: '12px', cursor: 'pointer', fontWeight: '600' }}
                >🔄 Refresh</button>
              </div>
            )}

            {/* Places grid */}
            {loading ? (
              <div style={s.empty}>
                <div style={{ fontSize: '36px', marginBottom: '12px' }}>⏳</div>
                <div style={{ fontWeight: '600', color: '#888' }}>Searching places...</div>
              </div>
            ) : places.length === 0 && search ? (
              <div style={s.empty}>
                <div style={{ fontSize: '48px', marginBottom: '16px' }}>😕</div>
                <div style={{ fontWeight: '700', fontSize: '16px', color: '#888' }}>No results for "{search}"</div>
                <div style={{ fontSize: '13px', marginTop: '6px', color: '#bbb' }}>Try a different name or location</div>
              </div>
            ) : (
              <div style={s.grid}>
                {places.map(place => (
                  <PlaceCard key={place.id} place={place} prediction={predictions[place.id]} />
                ))}
              </div>
            )}
          </>
        )}

        {/* ── ANALYTICS TAB ── */}
        {tab === 'Analytics' && <Analytics userCoords={userCoords} />}
      </div>

      {/* Profile Modal */}
      {profileOpen && <ProfileModal user={user} onClose={() => setProfile(false)} onLogout={logout} />}

      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </div>
  );
}
